import React, { useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AppContext';

/* ─── Inline styles / keyframes injected once ─── */
const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;1,9..40,300&family=Syne:wght@700;800&display=swap');

  :root {
    --ls-bg: #0a0a0b;
    --ls-bg2: #111113;
    --ls-bg3: #18181c;
    --ls-border: rgba(255,255,255,.07);
    --ls-border-h: rgba(255,255,255,.14);
    --ls-acc: #ff5c1a;
    --ls-acc2: #ff8c42;
    --ls-acc3: #ffb347;
    --ls-text: #f0ede8;
    --ls-text2: rgba(240,237,232,.5);
    --ls-text3: rgba(240,237,232,.3);
    --ls-green: #22c55e;
    --ls-blue: #3b82f6;
    --ls-purple: #a855f7;
    --ls-glass: rgba(255,255,255,.04);
    --ls-glass-h: rgba(255,255,255,.07);
  }

  .ls-page { max-width: 1200px; margin: 0 auto; padding: 0 28px; }

  /* Orb blobs */
  .ls-orb { position: absolute; border-radius: 50%; filter: blur(90px); pointer-events: none; }

  /* Glass card */
  .ls-card {
    background: var(--ls-glass);
    border: 1px solid var(--ls-border);
    border-radius: 20px;
    transition: background .25s, border-color .25s, transform .25s;
  }
  .ls-card:hover {
    background: var(--ls-glass-h);
    border-color: var(--ls-border-h);
    transform: translateY(-3px);
  }

  /* Pill badge */
  .ls-badge {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 5px 13px; border-radius: 100px;
    font-size: 12px; font-weight: 600; letter-spacing: .04em;
    border: 1px solid rgba(255,92,26,.25);
    background: rgba(255,92,26,.1); color: var(--ls-acc2);
  }

  /* Gradient text */
  .ls-gtext {
    background: linear-gradient(120deg, var(--ls-acc), var(--ls-acc3));
    -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  /* CTA buttons */
  .ls-btn-primary {
    display: inline-flex; align-items: center; gap: 8px;
    padding: 13px 28px; border-radius: 12px; font-size: 15px; font-weight: 600;
    background: linear-gradient(135deg, var(--ls-acc), var(--ls-acc2));
    color: #fff; border: none; cursor: pointer; text-decoration: none;
    transition: opacity .2s, transform .2s; letter-spacing: .01em;
  }
  .ls-btn-primary:hover { opacity: .88; transform: translateY(-1px); }

  .ls-btn-secondary {
    display: inline-flex; align-items: center; gap: 8px;
    padding: 13px 28px; border-radius: 12px; font-size: 15px; font-weight: 500;
    background: var(--ls-glass); color: var(--ls-text);
    border: 1px solid var(--ls-border-h); cursor: pointer; text-decoration: none;
    transition: background .2s, transform .2s;
  }
  .ls-btn-secondary:hover { background: var(--ls-glass-h); transform: translateY(-1px); }

  /* Stat number */
  .ls-stat-num {
    font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 800;
    background: linear-gradient(120deg, var(--ls-acc), var(--ls-acc3));
    -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  /* Float animation for hero images */
  @keyframes ls-float0 { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-8px)} }
  @keyframes ls-float1 { 0%,100%{transform:translateY(-5px)} 50%{transform:translateY(5px)} }
  @keyframes ls-float2 { 0%,100%{transform:translateY(-3px)} 50%{transform:translateY(7px)} }
  @keyframes ls-float3 { 0%,100%{transform:translateY(4px)} 50%{transform:translateY(-6px)} }
  .ls-flt0 { animation: ls-float0 4s ease-in-out infinite; }
  .ls-flt1 { animation: ls-float1 4.6s ease-in-out infinite; }
  .ls-flt2 { animation: ls-float2 3.8s ease-in-out infinite; }
  .ls-flt3 { animation: ls-float3 5s ease-in-out infinite; }

  /* Fade-in stagger */
  @keyframes ls-fadein { from{opacity:0;transform:translateY(22px)} to{opacity:1;transform:none} }
  .ls-fi { opacity: 0; animation: ls-fadein .7s ease forwards; }
  .ls-fi-1 { animation-delay: .1s }
  .ls-fi-2 { animation-delay: .22s }
  .ls-fi-3 { animation-delay: .34s }
  .ls-fi-4 { animation-delay: .46s }
  .ls-fi-5 { animation-delay: .58s }

  /* Category card overlay */
  .ls-cat-overlay {
    position: absolute; inset: 0;
    background: linear-gradient(to top, rgba(0,0,0,.85) 0%, rgba(0,0,0,.1) 55%, transparent 100%);
    transition: background .3s;
  }
  .ls-cat-wrap:hover .ls-cat-overlay {
    background: linear-gradient(to top, rgba(255,92,26,.7) 0%, rgba(0,0,0,.2) 60%, transparent 100%);
  }

  /* Marquee strip */
  @keyframes ls-marquee { from{transform:translateX(0)} to{transform:translateX(-50%)} }
  .ls-marquee-inner { display:flex; gap:0; animation: ls-marquee 22s linear infinite; width: max-content; }

  /* Feature badge chip */
  .ls-chip {
    font-size: 10px; font-weight: 700; letter-spacing: .06em;
    padding: 3px 9px; border-radius: 100px;
  }

  /* Divider line */
  .ls-divider { border: none; border-top: 1px solid var(--ls-border); margin: 0; }

  /* Section label */
  .ls-section-label {
    font-size: 11px; font-weight: 700; letter-spacing: .1em; text-transform: uppercase;
    color: var(--ls-acc); margin-bottom: 12px;
  }

  /* CTA section card */
  .ls-cta-card {
    border-radius: 28px; overflow: hidden; position: relative;
    background: var(--ls-bg3); border: 1px solid var(--ls-border);
  }
`;

export default function Home() {
  const { user } = useAuth();
  const stylesInjected = useRef(false);

  useEffect(() => {
    if (stylesInjected.current) return;
    stylesInjected.current = true;
    const el = document.createElement('style');
    el.textContent = STYLES;
    document.head.appendChild(el);
    return () => document.head.removeChild(el);
  }, []);

  const features = [
    { i: '📍', t: 'Hyperlocal Stock Pulse', d: 'Real-time distance & travel time to nearby vendors', b: '⭐ UNIQUE', c: 'var(--ls-acc)' },
    { i: '🤝', t: 'Group Buying', d: '5+ locals unlock group discounts within 24 hours', b: 'SOCIAL', c: 'var(--ls-green)' },
    { i: '💬', t: 'Negotiate Now', d: 'Chatbot bargains within vendor-set discount range', b: '⭐ UNIQUE', c: 'var(--ls-acc)' },
    { i: '📱', t: 'WhatsApp Orders', d: 'One-click ordering with auto-generated messages', b: 'DIRECT', c: 'var(--ls-green)' },
    { i: '💰', t: 'Budget Assistant', d: 'Set limits, get alerts, find cheaper alternatives', b: 'SMART', c: 'var(--ls-blue)' },
    { i: '⭐', t: 'Vendor Trust Score', d: 'Transparent ratings from reviews & delivery data', b: 'VERIFIED', c: 'var(--ls-acc3)' },
    { i: '🌱', t: 'Sustainability Score', d: 'Eco-ratings with greener product suggestions', b: 'ECO', c: 'var(--ls-green)' },
    { i: '📊', t: 'Expense Tracker', d: 'Category-wise spending insights and reports', b: 'INSIGHTS', c: 'var(--ls-purple)' },
  ];

  const cats = [
    { n: 'Vegetables', img: 'https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80', c: '240+ products' },
    { n: 'Fruits', img: 'https://images.unsplash.com/photo-1610832958506-aa56368176cf?w=400&q=80', c: '180+ products' },
    { n: 'Dairy', img: 'https://images.unsplash.com/photo-1563636619-e9143da7973b?w=400&q=80', c: '90+ products' },
    { n: 'Food', img: 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=400&q=80', c: '320+ products' },
    { n: 'Handicrafts', img: 'https://images.unsplash.com/photo-1606722590583-6951b5ea92ad?w=400&q=80', c: '150+ products' },
    { n: 'Clothing', img: 'https://images.unsplash.com/photo-1445205170230-053b83016050?w=400&q=80', c: '200+ products' },
  ];

  const heroImgs = [
